// src/components/Navbar.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { Search, X, Menu } from "lucide-react";
import logo from "../assets/logo.png";

const pages = [
  { name: "Home", path: "/" },
  { name: "About", path: "/about" },
  { name: "Domains", path: "/domains" },
  { name: "Vision", path: "/vision" },
  { name: "Purpose", path: "/purpose" },
  { name: "Team", path: "/team" },
  { name: "Careers", path: "/careers" },
  { name: "Contact", path: "/contact" },
];

function Navbar({ onSearchClick }) {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  return (
    <nav className="w-full bg-black text-white fixed top-0 z-50 shadow-md">
      <div className="max-w-7xl mx-auto px-6 md:px-10 flex justify-between items-center h-16">
        {/* Logo */}
        <div className="flex items-center space-x-2">
          <img src={logo} alt="Godemar Logo" className="w-10 h-10" />
          <span className="font-bold text-xl">Godemar’s Empire</span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-6">
          {pages.map((page) => (
            <Link
              key={page.path}
              to={page.path}
              className="hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            >
              {page.name}
            </Link>
          ))}
          {/* Search Button */}
          <button
            onClick={onSearchClick}
            className="ml-2 p-2 hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
        </div>

        {/* Mobile Hamburger */}
        <div className="md:hidden flex items-center">
          <button
            onClick={onSearchClick}
            className="mr-2 p-2"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            aria-label="Toggle menu"
          >
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-black text-white px-6 py-4 space-y-4">
          <div className="flex justify-between items-center">
            <span className="font-bold">Menu</span>
            <button
              onClick={() => setIsMenuOpen(false)}
              className="p-2 hover:text-red-500 focus:outline focus:outline-2 focus:outline-red-500 rounded"
              aria-label="Close menu"
            >
              <X size={20} />
            </button>
          </div>
          {pages.map((page) => (
            <Link
              key={page.path}
              to={page.path}
              onClick={() => setIsMenuOpen(false)}
              className="block hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded"
            >
              {page.name}
            </Link>
          ))}
        </div>
      )}
    </nav>
  );
}

export default Navbar;
